void rs_syndrome_n46_r30( SYNDROME_T * syndromes , const uint8_t * cdw )
{
    uint32_t regs[8] = {0};
    for(int i=0;i<46;i++) {
        uint32_t m0[8];
        bs_gf256_multab( m0 , cdw[i] );
        for(int j=0;j<8;j++) { regs[j] ^= bs_gf256_mul( rs_parity_mat_n46_r30[i*8+j], m0 ); }
    }

    uint8_t * ptr = (uint8_t *)regs;
    for(int i=0;i<30;i++) { syndromes[i] = ptr[i]; }
}

